const express = require('express');
const app = express();
const bodyParser = require('body-parser');
const fs = require('fs');
const path = require('path');

app.use(bodyParser.json());

const loadPlugins = () => {
  const plugins = [];
  const pluginDir = process.env.PLUGIN_DIR || './plugins';
  const pluginFiles = fs.readdirSync(pluginDir);

  pluginFiles.forEach(file => {
    if (file.endsWith('.js')) {
      const pluginPath = path.join(pluginDir, file);
      const plugin = require(pluginPath);
      if (typeof plugin === 'function') {
        plugins.push(plugin);
      }
    }
  });

  const envPluginCode = process.env.PLUGIN_CODE;
  if (envPluginCode) {
    try {
      const plugin = eval(envPluginCode);
      if (typeof plugin === 'function') {
        plugins.push(plugin);
      }
    } catch (error) {
      console.error('Error loading plugin from environment variable:', error);
    }
  }

  return plugins;
};

const plugins = loadPlugins();

app.use((req, res, next) => {
  plugins.forEach(plugin => {
    try {
      plugin(req, res);
    } catch (error) {
      console.error('Error executing plugin:', error);
    }
  });
  next();
});

app.all('*', (req, res) => {
  res.send('API Gateway Response');
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`API Gateway running on port ${PORT}`);
});